/* ===========================================================================
 * Loading indicator while results are fetched
 *
 * render() clears the results container and then awaits the route data. While
 * that fetch is in flight the user must see a lightweight "work in progress"
 * placeholder (e.g. "Loading…" or a skeleton element) rather than an EMPTY
 * container — otherwise a slow connection makes the UI look broken or empty.
 * The placeholder must be replaced once data arrives (renderBrowse /
 * renderSearch rebuild the table) and also on error (the catch block sets the
 * error text). The render-race guard must still keep working underneath it.
 *
 * These tests hold the fetch open so the in-flight state is observable, then
 * release it and assert the placeholder is cleared on both the success and
 * error paths. They FAIL against the current code (which clears `.results` and
 * leaves it empty during the fetch) and PASS once a loading placeholder is
 * rendered before the await.
 * ========================================================================= */
describe('loading indicator while results are fetched', () => {
  /**
   * Build the recognizable success `Response` for a browse/search GET URL,
   * mirroring the shared stub so post-release assertions can reuse the
   * familiar 'child-of-…' / 'result-for-…' markers.
   */
  function successResponseFor(url: string): Response {
    const u = String(url);
    if (u.includes('/browse')) {
      const path = decodeURIComponent(u.split('path=')[1] ?? '');
      const childName = 'child-of-' + (path || 'root');
      return mockResponse({
        body: browseResult({
          path,
          entries: [fileEntry({ name: childName, path: joinPathHelper(path, childName) })],
          fileCount: 1,
          totalSize: 10,
        }),
      });
    }
    if (u.includes('/search')) {
      const afterQuery = u.slice(u.indexOf('query=') + 6);
      const query = decodeURIComponent(afterQuery.split('&')[0]);
      return mockResponse({
        body: {
          query,
          path: '',
          results: [fileEntry({ name: 'result-for-' + query, path: joinPathHelper('docs', 'result-for-' + query) })],
        } as SearchResult,
      });
    }
    return mockResponse({ status: 200, body: {} });
  }

  /**
   * Hold EVERY GET fetch until `release()` is called, then resolve each with
   * `respond(url)`. Non-GET requests resolve immediately as 200. Lets a test
   * observe the in-flight loading state and then choose success or failure.
   */
  function holdGetsUntil(
    respond: (url: string) => Response,
  ): { release: () => void } {
    let release!: () => void;
    const gate = new Promise<void>((resolve) => {
      release = resolve;
    });
    fetchMock.mockImplementation(async (url: string, init?: RequestInit) => {
      const method = (init?.method ?? 'GET').toUpperCase();
      if (method !== 'GET') {
        return mockResponse({ status: 200, body: {} });
      }
      await gate; // suspend every GET until the test releases it
      return respond(String(url));
    });
    return { release };
  }

  /**
   * True if `el` currently shows a loading placeholder — either loading text
   * (e.g. "Loading…") or a skeleton/spinner element whose class hints at a
   * loading state. Tolerant of whichever lightweight placeholder the
   * implementation chooses, but strict enough to FAIL if the container is
   * empty or merely holds an empty/meaningless node (the current bug).
   */
  function showsLoadingPlaceholder(el: HTMLElement): boolean {
    const text = (el.textContent ?? '').trim();
    if (/loading/i.test(text)) {
      return true;
    }
    for (const node of Array.from(el.querySelectorAll('*'))) {
      const cls = (node as HTMLElement).className;
      if (typeof cls === 'string' && /(loading|skeleton|spinner)/i.test(cls)) {
        return true;
      }
    }
    return false;
  }

  it('shows a loading placeholder (not an empty container) while a browse fetch is in flight', async () => {
    const { release } = holdGetsUntil(successResponseFor);
    const { results } = setup({ hash: toBrowseHash('home') });
    // startApp → init → render() runs synchronously up to the held await; the
    // results container must show a loading placeholder rather than be empty.
    expect(showsLoadingPlaceholder(results)).toBe(true);
    expect(results.querySelector('table')).toBeNull();

    release();
    await flush();

    // The placeholder is replaced by the real browse table on success.
    expect(showsLoadingPlaceholder(results)).toBe(false);
    expect(results.querySelector('table')).toBeTruthy();
    expect(results.textContent).toContain('child-of-home');
  });

  it('shows a loading placeholder while a search fetch is in flight', async () => {
    const { release } = holdGetsUntil(successResponseFor);
    const { results } = setup({ hash: toSearchHash('kittens', '') });
    expect(showsLoadingPlaceholder(results)).toBe(true);
    expect(results.querySelector('table')).toBeNull();

    release();
    await flush();

    expect(showsLoadingPlaceholder(results)).toBe(false);
    expect(results.querySelector('table')).toBeTruthy();
    expect(results.textContent).toContain('result-for-kittens');
  });

  it('replaces the loading placeholder with the error message when the fetch fails', async () => {
    const { release } = holdGetsUntil(() => mockResponse({ status: 500, text: 'boom' }));
    const { results } = setup({ hash: toBrowseHash('home') });
    expect(showsLoadingPlaceholder(results)).toBe(true);

    release();
    await flush();

    // The placeholder is gone and the error is surfaced (no table).
    expect(showsLoadingPlaceholder(results)).toBe(false);
    expect(results.querySelector('table')).toBeNull();
    expect(results.textContent).toContain('boom');
  });

  it('re-shows the loading placeholder (replacing a prior table) when a new navigation starts a fetch', async () => {
    // Start with a fully-rendered browse table for 'first'.
    const { results } = setup({ hash: toBrowseHash('first') });
    await flush();
    expect(results.querySelector('table')).toBeTruthy();
    expect(showsLoadingPlaceholder(results)).toBe(false);

    // Hold subsequent fetches and navigate to a new route. The new render must
    // clear the now-stale table and show the loading placeholder while it
    // fetches — otherwise the user sees a stale table that no longer matches
    // the route they just clicked.
    const { release } = holdGetsUntil(successResponseFor);
    navigate(toBrowseHash('second'));
    // hashchange dispatches synchronously in happy-dom → render() runs up to
    // the held await.
    expect(showsLoadingPlaceholder(results)).toBe(true);
    expect(results.querySelector('table')).toBeNull();

    release();
    await flush();
    expect(showsLoadingPlaceholder(results)).toBe(false);
    expect(results.textContent).toContain('child-of-second');
  });
});

